<?php
require __DIR__.'/config.php';require_login();
$userId=(int)$_SESSION['user']['id'];$key='profile_'.$userId;$stmt=db()->prepare('SELECT setting_value FROM settings WHERE setting_key=?');$stmt->execute([$key]);$profile=json_decode((string)$stmt->fetchColumn(),true)?:[];$error='';$success='';
$defaults=['phone'=>'','organization'=>'Sofitel İstanbul Taksim','address'=>'','state'=>'','zip_code'=>'','country'=>'Türkiye','language'=>'Türkçe','timezone'=>'Europe/Istanbul','currency'=>'TRY','avatar'=>''];$profile=array_merge($defaults,$profile);
if($_SERVER['REQUEST_METHOD']==='POST'){
 verify_csrf();$action=$_POST['action']??'save';
 if($action==='reset_avatar'){$old=$profile['avatar'];if($old&&is_file(__DIR__.'/'.$old))@unlink(__DIR__.'/'.$old);$profile['avatar']='';$success='Profil fotoğrafı kaldırıldı.';}
 elseif($action==='upload_avatar'){
  if(empty($_FILES['avatar']['tmp_name'])||$_FILES['avatar']['error']!==UPLOAD_ERR_OK)$error='Yüklenecek fotoğrafı seçin.';
  elseif($_FILES['avatar']['size']>819200)$error='Fotoğraf en fazla 800 KB olabilir.';
  else{$mime=(new finfo(FILEINFO_MIME_TYPE))->file($_FILES['avatar']['tmp_name']);$types=['image/jpeg'=>'jpg','image/png'=>'png','image/gif'=>'gif'];if(!isset($types[$mime]))$error='Yalnızca JPG, PNG veya GIF yükleyebilirsiniz.';else{$dir=__DIR__.'/assets/uploads/profiles';if(!is_dir($dir))mkdir($dir,0775,true);$file='user-'.$userId.'-'.bin2hex(random_bytes(6)).'.'.$types[$mime];if(!move_uploaded_file($_FILES['avatar']['tmp_name'],$dir.'/'.$file))$error='Fotoğraf kaydedilemedi.';else{if($profile['avatar']&&is_file(__DIR__.'/'.$profile['avatar']))@unlink(__DIR__.'/'.$profile['avatar']);$profile['avatar']='assets/uploads/profiles/'.$file;$success='Profil fotoğrafı güncellendi.';}}}
 }
  elseif($action==='password'){
   $password=$_POST['password']??'';$confirm=$_POST['password_confirm']??'';
   if(strlen($password)<6)$error='Şifre en az 6 karakter olmalıdır.';
   elseif($password!==$confirm)$error='Şifre ve şifre tekrarı aynı olmalıdır.';
   else{$update=db()->prepare('UPDATE users SET password_hash=? WHERE id=?');$update->execute([password_hash($password,PASSWORD_DEFAULT),$userId]);$success='Şifreniz değiştirildi.';}
  }
  else{
  $name=trim($_POST['name']??'');$email=trim(strtolower($_POST['email']??''));if($name===''||!filter_var($email,FILTER_VALIDATE_EMAIL))$error='Geçerli ad ve e-posta girin.';else{foreach(['phone','organization','address','state','zip_code','country','language','timezone','currency'] as $field)$profile[$field]=trim($_POST[$field]??'');try{$update=db()->prepare('UPDATE users SET name=?,email=? WHERE id=?');$update->execute([$name,$email,$userId]);$_SESSION['user']['name']=$name;$_SESSION['user']['email']=$email;$success='Profil bilgileri kaydedildi.';}catch(PDOException $e){$error='E-posta adresi başka bir kullanıcı tarafından kullanılıyor.';}}
 }
 if(!$error){$upsert=db()->getAttribute(PDO::ATTR_DRIVER_NAME)==='mysql'?'INSERT INTO settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)':'INSERT INTO settings(setting_key,setting_value) VALUES(?,?) ON CONFLICT(setting_key) DO UPDATE SET setting_value=excluded.setting_value';$save=db()->prepare($upsert);$save->execute([$key,json_encode($profile,JSON_UNESCAPED_UNICODE)]);}
}
?>
<!doctype html><html lang="tr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Profilim | <?=APP_NAME?></title><link rel="icon" href="<?=url('assets/favicon.png')?>"><link rel="stylesheet" href="<?=url('assets/style.css')?>"><link rel="stylesheet" href="<?=url('assets/amerce/fonts/fonts.css')?>"><link rel="stylesheet" href="<?=url('assets/vuexy-inspired.css')?>"><link rel="stylesheet" href="<?=url('assets/profile.css')?>"><link rel="stylesheet" href="<?=url('assets/green-buttons.css?v=20260712-3')?>"><script src="<?=url('assets/theme.js?v=20260712-2')?>"></script></head><body><header><a class="brand brand-back-link" href="<?=url('index.php')?>" onclick="if(document.referrer&&history.length>1){history.back();return false}" title="Önceki sayfaya dön"><img class="profile-brand-logo" style="display:block!important;width:38px!important;height:38px!important;object-fit:contain!important" src="<?=url('assets/kirpisoftware-logo-transparent-v2.png')?>" alt="Kirpisoft"><span><b>Lost &amp; Found</b></span></a><a class="profile-home-link" href="<?=url('index.php')?>" title="Ana sayfa" aria-label="Ana sayfa"><span aria-hidden="true">⌂</span></a></header><main class="profile-container"><nav class="profile-tabs"><a class="profile-tab active" data-tab="account" href="#account"><span aria-hidden="true">♙</span> Hesap</a><a class="profile-tab" data-tab="security" href="#security"><span aria-hidden="true">♙</span> Güvenlik</a></nav><section id="account-panel" class="profile-card profile-tab-panel"><?php if($error):?><div class="alert"><?=e($error)?></div><?php endif?><?php if($success):?><div class="profile-success"><?=e($success)?></div><?php endif?><div class="avatar-editor"><div class="profile-photo"><?php if($profile['avatar']):?><img src="<?=url($profile['avatar'])?>" alt="Profil fotoğrafı"><?php else:?><span><?=e(mb_strtoupper(mb_substr($_SESSION['user']['name'],0,1)))?></span><?php endif?></div><div><form class="photo-actions" method="post" enctype="multipart/form-data"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="upload_avatar"><label class="upload-button">Yeni fotoğraf yükle<input type="file" name="avatar" accept="image/jpeg,image/png,image/gif" onchange="this.form.submit()"></label></form><form method="post" class="reset-form"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="reset_avatar"><button type="submit" class="reset-button">Sıfırla</button></form><p>JPG, GIF veya PNG. En fazla 800 KB.</p></div></div><form class="profile-form" method="post"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="save"><label>Ad Soyad<input name="name" value="<?=e($_SESSION['user']['name'])?>" required></label><label>E-posta<input type="email" name="email" value="<?=e($_SESSION['user']['email'])?>" required></label><label>Telefon<input name="phone" value="<?=e($profile['phone'])?>"></label><label>Kurum<input name="organization" value="<?=e($profile['organization'])?>"></label><label>Adres<input name="address" value="<?=e($profile['address'])?>"></label><label>Şehir / İl<input name="state" value="<?=e($profile['state'])?>"></label><label>Posta Kodu<input name="zip_code" value="<?=e($profile['zip_code'])?>"></label><label>Ülke<input name="country" value="<?=e($profile['country'])?>"></label><label>Dil<select name="language"><option>Türkçe</option><option>English</option></select></label><label>Saat Dilimi<input name="timezone" value="<?=e($profile['timezone'])?>"></label><label>Para Birimi<input name="currency" value="<?=e($profile['currency'])?>"></label><div class="profile-actions"><button class="save-profile">Kaydet</button><a href="<?=url('index.php')?>">Vazgeç</a></div></form></section><section id="security-panel" class="profile-card profile-tab-panel" hidden><?php if($error):?><div class="alert"><?=e($error)?></div><?php endif?><?php if($success):?><div class="profile-success"><?=e($success)?></div><?php endif?><h2>Şifre Değiştir</h2><p>Hesabınız için en az 6 karakterli yeni bir şifre belirleyin.</p><form class="password-form" method="post" action="<?=url('profile.php#security')?>"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="password"><label>Yeni şifre<input type="password" name="password" minlength="6" autocomplete="new-password" required></label><label>Yeni şifre tekrar<input type="password" name="password_confirm" minlength="6" autocomplete="new-password" required></label><button class="save-profile">Kaydet</button></form></section></main><script>const tabs=[...document.querySelectorAll('.profile-tab')],panels={account:document.getElementById('account-panel'),security:document.getElementById('security-panel')};function showTab(name){const selected=panels[name]?name:'account';tabs.forEach(tab=>tab.classList.toggle('active',tab.dataset.tab===selected));Object.entries(panels).forEach(([key,panel])=>panel.hidden=key!==selected)}tabs.forEach(tab=>tab.addEventListener('click',event=>{event.preventDefault();history.replaceState(null,'','#'+tab.dataset.tab);showTab(tab.dataset.tab)}));showTab(location.hash==='#security'?'security':'account');</script></body></html>
